import{c as s,Q as n,j as l,m as p}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"反向代理与网关:Nginx、Cloudflare、API Gateway 的位置","description":"","frontmatter":{},"headers":[],"relativePath":"cloudBasicsLearning/07-反向代理与网关.md","filePath":"cloudBasicsLearning/07-反向代理与网关.md","lastUpdated":1779015580000}'),i={name:"cloudBasicsLearning/07-反向代理与网关.md"};function e(t,a,o,c,d,r){return n(),l("div",null,[...a[0]||(a[0]=[p(`<h1 id="反向代理与网关-nginx、cloudflare、api-gateway-的位置" tabindex="-1">反向代理与网关:Nginx、Cloudflare、API Gateway 的位置 <a class="header-anchor" href="#反向代理与网关-nginx、cloudflare、api-gateway-的位置" aria-label="Permalink to &quot;反向代理与网关:Nginx、Cloudflare、API Gateway 的位置&quot;">​</a></h1><blockquote><p>一句话解释:<strong>反向代理和网关都是站在用户请求前面的入口层,帮后面的服务接请求、转发请求、做统一控制</strong>。</p></blockquote><p>你可以把它理解成一家小公司的前台。用户不会直接冲进每个办公室找人,而是先到前台说明来意。前台根据路径、域名、登录状态、规则,把请求转给官网、API、后台管理、文件服务,或者直接拒绝。</p><p>反向代理更偏&quot;把请求转到正确的后端&quot;;网关更偏&quot;在进入后端前做统一治理&quot;。实际产品里二者经常重叠,Nginx、Caddy、Traefik、Cloudflare、API Gateway、Ingress Controller 都可能承担其中一部分工作。</p><p>最容易混淆的是:<strong>反向代理不是负载均衡的同义词,网关也不是后端服务本身</strong>。负载均衡是把流量分给多台机器的一种能力;反向代理可以做负载均衡,也可以只转发到一台服务器。网关可以做鉴权、限流、路由、日志,但真正的业务逻辑仍然在后端服务里。</p><hr><h2 id="一、放在系统哪里" tabindex="-1">一、放在系统哪里 <a class="header-anchor" href="#一、放在系统哪里" aria-label="Permalink to &quot;一、放在系统哪里&quot;">​</a></h2><p>一个小团队常见链路可能长这样:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器 / App</span></span>
<span class="line"><span>  -&gt; DNS</span></span>
<span class="line"><span>  -&gt; CDN / WAF</span></span>
<span class="line"><span>  -&gt; 反向代理或网关</span></span>
<span class="line"><span>  -&gt; Web 服务 / API 服务 / 管理后台 / 文件服务</span></span>
<span class="line"><span>  -&gt; 数据库 / 缓存 / 队列</span></span></code></pre></div><p>反向代理和网关通常在服务入口处。它们的典型工作包括:</p><ul><li>根据域名转发:<code>www.example.com</code> 到官网,<code>api.example.com</code> 到 API。</li><li>根据路径转发:<code>/api/*</code> 到后端,<code>/admin/*</code> 到后台,<code>/static/*</code> 到静态文件。</li><li>统一处理 HTTPS 证书。</li><li>记录访问日志。</li><li>做基础限流。</li><li>给后端隐藏真实 IP 和端口。</li><li>在多台后端之间做负载均衡。</li></ul><p>一个真实场景:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你有一台云服务器,上面跑了三个服务:</span></span>
<span class="line"><span>  - Next.js 前端:localhost:3000</span></span>
<span class="line"><span>  - Node API:localhost:4000</span></span>
<span class="line"><span>  - Admin 后台:localhost:5000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>你不希望用户记端口:</span></span>
<span class="line"><span>  - https://example.com       -&gt; localhost:3000</span></span>
<span class="line"><span>  - https://example.com/api   -&gt; localhost:4000</span></span>
<span class="line"><span>  - https://admin.example.com -&gt; localhost:5000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>这时 Nginx / Caddy 就可以作为反向代理。</span></span></code></pre></div><p>如果项目变成微服务,入口层就更重要:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/api/users     -&gt; 用户服务</span></span>
<span class="line"><span>/api/billing   -&gt; 账单服务</span></span>
<span class="line"><span>/api/uploads   -&gt; 上传服务</span></span>
<span class="line"><span>/api/internal  -&gt; 只允许内网访问</span></span></code></pre></div><p>这时 API Gateway 会把路由、鉴权、限流、日志、灰度发布等入口能力集中管理。否则每个服务都自己写一套入口逻辑,很快就会混乱。</p><hr><h2 id="二、常见套餐和使用限制" tabindex="-1">二、常见套餐和使用限制 <a class="header-anchor" href="#二、常见套餐和使用限制" aria-label="Permalink to &quot;二、常见套餐和使用限制&quot;">​</a></h2><p>反向代理可以是你自己在服务器上装的 Nginx,也可以是云厂商托管的网关服务。两者限制很不一样。</p><p>自己部署 Nginx / Caddy 的限制通常是机器资源:</p><ul><li>云服务器 CPU 和内存。</li><li>带宽上限。</li><li>文件描述符和连接数。</li><li>TLS 握手带来的 CPU 消耗。</li><li>日志占用磁盘。</li><li>你自己负责升级、配置、证书、故障恢复。</li></ul><p>托管 API Gateway / 边缘网关的限制通常是套餐维度:</p><ul><li>请求数。</li><li>每秒请求数或突发流量。</li><li>路由数量。</li><li>自定义域名数量。</li><li>插件或策略数量。</li><li>鉴权、限流、转换规则是否收费。</li><li>日志保留时间。</li><li>跨区域或公网出站流量费用。</li></ul><p>小团队最容易踩的坑有三个。</p><p>第一,把所有请求都穿过网关,但没看请求数计费。一个页面加载可能触发 10 个 API 请求,10000 次页面访问就可能变成 100000 次网关请求。</p><p>第二,在网关上做了复杂转换。比如请求体改写、响应体改写、JWT 校验、外部鉴权调用、动态路由匹配。每个动作都可能增加延迟,也可能进入更高套餐。</p><p>第三,入口层配置和应用配置不一致。比如网关允许上传 50 MB,后端只允许 10 MB;网关超时时间 30 秒,后端任务要跑 60 秒;网关转发了用户真实 IP,应用却没有正确读取,导致限流全部按网关 IP 计算。</p><hr><h2 id="三、小团队建议" tabindex="-1">三、小团队建议 <a class="header-anchor" href="#三、小团队建议" aria-label="Permalink to &quot;三、小团队建议&quot;">​</a></h2><p>如果你只有一个 Web 应用和一个 API,不要一开始就上复杂网关。一个托管平台自带的路由能力,或者一台服务器上的 Nginx / Caddy,通常已经够用。</p><p>小团队更应该优先把入口边界想清楚:</p><ul><li>哪些域名对外开放。</li><li>哪些路径是静态资源。</li><li>哪些路径是 API。</li><li>哪些路径需要登录。</li><li>哪些路径只允许管理员访问。</li><li>哪些请求应该限流。</li><li>日志里要保留哪些字段,例如 path、status、latency、user-agent、真实 IP。</li></ul><p>一个保守起点:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com</span></span>
<span class="line"><span>  -&gt; CDN</span></span>
<span class="line"><span>  -&gt; Web 前端</span></span>
<span class="line"><span></span></span>
<span class="line"><span>api.example.com</span></span>
<span class="line"><span>  -&gt; 网关 / 反向代理</span></span>
<span class="line"><span>  -&gt; API 服务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>admin.example.com</span></span>
<span class="line"><span>  -&gt; 反向代理</span></span>
<span class="line"><span>  -&gt; 管理后台</span></span></code></pre></div><p>这样做的好处是边界清楚。前端静态资源走 CDN,API 单独观察,后台单独加访问控制。以后要加 WAF、限流、灰度发布,也比较容易分层处理。</p><p>什么时候该升级到更专业的网关?</p><ul><li>API 变多,路径和版本管理开始混乱。</li><li>有多个后端服务,需要统一鉴权和限流。</li><li>需要按客户、Token、IP、区域做不同策略。</li><li>需要完整访问日志和审计。</li><li>需要灰度发布、蓝绿发布、熔断、重试。</li><li>自己维护 Nginx 已经成为风险点。</li></ul><p>最低限度的护栏是:</p><ul><li>入口层配置要纳入版本管理,不要只靠控制台手点。</li><li>所有公网入口都要有 HTTPS。</li><li>管理后台不要和公开 API 混在同一个无保护路径下。</li><li>上传大小、超时时间、请求体限制要和后端一致。</li><li>保留基础访问日志,否则出问题时无法判断是用户、网关还是后端慢。</li></ul><hr><h2 id="四、一句话总结" tabindex="-1">四、一句话总结 <a class="header-anchor" href="#四、一句话总结" aria-label="Permalink to &quot;四、一句话总结&quot;">​</a></h2><p><strong>反向代理和网关是系统入口的交通规则层;小团队不需要一开始就复杂化,但必须清楚请求从哪个入口进来、被转到哪里、在哪里做鉴权、限流和日志。</strong></p>`,42)])])}const u=s(i,[["render",e]]);export{g as __pageData,u as default};
